import { useState, useCallback } from "react";
import { useApp } from "../context/AppContext";
import { loginAPI } from "../services/api";
import Input from "../components/Input";
import Button from "../components/Button";

export default function LoginPage() {
  const { dispatch } = useApp();
  const [form, setForm] = useState({ email: "", password: "" });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState("");

  const validate = () => {
    const e = {};
    if (!form.email) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Enter a valid email";
    if (!form.password) e.password = "Password is required";
    else if (form.password.length < 5) e.password = "Minimum 5 characters";
    return e;
  };

  const handleChange = useCallback((e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  }, []);

  const handleSubmit = async () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }
    setLoading(true);
    setApiError("");
    try {
      const { user } = await loginAPI(form.email, form.password);
      dispatch({ type: "LOGIN", payload: user });
    } catch (err) {
      setApiError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.wrap}>
      {/* Left panel */}
      <div style={styles.left}>
        <div style={styles.brand}>
          <div style={styles.logo}>◆</div>
          <div style={styles.tagline}>Where luxury finds its home</div>
          <div style={styles.divider} />
          <div style={styles.hotelName}>GrandLuxe Hotels & Resorts</div>
        </div>
      </div>

      {/* Right panel */}
      <div style={styles.right}>
        <div style={styles.formWrap}>
          <h2 style={styles.heading}>Welcome back</h2>
          <p style={styles.subheading}>Sign in to manage your reservations</p>

          <div style={styles.hint}>
            <strong>Demo:</strong> demo@hotel.com / demo123
          </div>

          {apiError && (
            <div style={styles.apiErr}>{apiError}</div>
          )}

          <Input
            label="Email Address"
            type="email"
            name="email"
            placeholder="you@example.com"
            value={form.email}
            onChange={handleChange}
            onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            error={errors.email}
          />
          <Input
            label="Password"
            type="password"
            name="password"
            placeholder="••••••••"
            value={form.password}
            onChange={handleChange}
            onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            error={errors.password}
          />

          <Button variant="primary" fullWidth loading={loading} onClick={handleSubmit}>
            Sign In →
          </Button>
        </div>
      </div>
    </div>
  );
}

const styles = {
  wrap: { minHeight: "100vh", display: "grid", gridTemplateColumns: "1fr 1fr" },
  left: {
    background: "var(--ink)", display: "flex", alignItems: "center",
    justifyContent: "center", padding: 60,
    backgroundImage: "radial-gradient(ellipse at 30% 70%, rgba(201,168,76,0.15) 0%, transparent 60%), radial-gradient(ellipse at 80% 20%, rgba(201,168,76,0.08) 0%, transparent 50%)",
  },
  brand: { textAlign: "center" },
  logo: { fontFamily: "'Cormorant Garamond', serif", fontSize: 72, color: "var(--gold)", lineHeight: 1, marginBottom: 16 },
  tagline: { fontFamily: "'Cormorant Garamond', serif", fontSize: 22, color: "rgba(255,255,255,0.6)", fontStyle: "italic", letterSpacing: "0.05em" },
  divider: { width: 60, height: 1, background: "var(--gold)", opacity: 0.5, margin: "20px auto" },
  hotelName: { fontSize: 13, color: "rgba(255,255,255,0.35)", letterSpacing: "0.2em", textTransform: "uppercase" },
  right: { background: "var(--surface)", display: "flex", alignItems: "center", justifyContent: "center", padding: 60 },
  formWrap: { width: "100%", maxWidth: 380 },
  heading: { fontFamily: "'Cormorant Garamond', serif", fontSize: 36, fontWeight: 300, marginBottom: 8 },
  subheading: { color: "var(--muted)", fontSize: 14, marginBottom: 32 },
  hint: { background: "var(--warm)", border: "1px solid var(--border)", borderRadius: "var(--radius)", padding: "12px 16px", marginBottom: 24, fontSize: 13, color: "var(--muted)" },
  apiErr: { background: "#fde8e8", color: "var(--error)", padding: "12px 16px", borderRadius: "var(--radius)", marginBottom: 20, fontSize: 13 },
};
